// PUBMED COUNT - juste retmax=0 pour avoir le total
const input = $('Extract Params').first().json;
const query = encodeURIComponent(input.pubmed_query || '');
const PROXY = 'http://host.docker.internal:3456';

if (!query) {
  return [{ json: { _source: 'pubmed', count: 0, query: '' } }];
}

try {
  const url = `https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esearch.fcgi?db=pubmed&term=${query}&retmax=0&retmode=json`;
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: PROXY + '?url=' + encodeURIComponent(url),
    timeout: 30000
  });
  const count = parseInt((resp.esearchresult || {}).count || '0');
  console.log('PubMed count: ' + count);
  return [{ json: { _source: 'pubmed', count, query: input.pubmed_query } }];
} catch(e) {
  console.log('PubMed count error: ' + e.message);
  return [{ json: { _source: 'pubmed', count: 0, error: e.message } }];
}

