// CROSSREF COUNT - rows=0 pour avoir message.total-results
const input = $('Extract Params').first().json;
const query = encodeURIComponent(input.crossref_query || '');
const PROXY = 'http://host.docker.internal:3456';

if (!query) {
  return [{ json: { _source: 'crossref', count: 0, query: '' } }];
}

try {
  const url = `https://api.crossref.org/works?query=${query}&rows=0&mailto=ultralab@review.org`;
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: PROXY + '?url=' + encodeURIComponent(url),
    timeout: 30000
  });
  const count = parseInt((resp.message || {})['total-results'] || '0');
  console.log('Crossref count: ' + count);
  return [{ json: { _source: 'crossref', count, query: input.crossref_query } }];
} catch(e) {
  console.log('Crossref count error: ' + e.message);
  return [{ json: { _source: 'crossref', count: 0, error: e.message } }];
}

// Combine les 3 counts en un seul JSON avec total et warnings
const items = $input.all().map(i => i.json);
const counts = { pubmed: 0, openalex: 0, crossref: 0 };
const errors = {};

for (const item of items) {
  const src = item._source;
  if (src && counts[src] !== undefined) {
    counts[src] = item.count || 0;
    if (item.error) errors[src] = item.error;
  }
}

const total = counts.pubmed + counts.openalex + counts.crossref;
const warnings = [];

if (total === 0) {
  warnings.push('Aucun resultat trouve sur les 3 bases. Verifiez votre equation.');
}
if (total > 10000) {
  warnings.push('Plus de 10 000 resultats. Le traitement risque de saturer la RAM. Pensez a poser un cap.');
}
if (total > 50000) {
  warnings.push('CRITIQUE : plus de 50 000 resultats. Tres fortement deconseille sans cap strict.');
}
if (Object.keys(errors).length > 0) {
  warnings.push('Erreurs API : ' + JSON.stringify(errors));
}

console.log('Count summary: pubmed=' + counts.pubmed + ' openalex=' + counts.openalex + ' crossref=' + counts.crossref + ' total=' + total);

return [{ json: {
  action: 'count',
  success: true,
  pubmed_count: counts.pubmed,
  openalex_count: counts.openalex,
  crossref_count: counts.crossref,
  total,
  warnings,
  errors
}}];

// PUBMED FETCH avec cap par source
const input = $('Extract Params').first().json;
const query = encodeURIComponent(input.pubmed_query || '');
const PROXY = 'http://host.docker.internal:3456';
const BATCH = 200;
const cap = parseInt(input.cap_pubmed) || 0;  // 0 = pas de cap par base
const unlimited = input.unlimited === true;
const MAX_RESULTS = unlimited ? Number.MAX_SAFE_INTEGER : (cap > 0 ? cap : 1000);

let allArticles = [];

if (!query) {
  return [{ json: { _source: 'pubmed', _empty: true } }];
}

try {
  const searchTarget = `https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esearch.fcgi?db=pubmed&term=${query}&retmax=0&usehistory=y&retmode=json`;
  const searchResp = await this.helpers.httpRequest({
    method: 'GET',
    url: PROXY + '?url=' + encodeURIComponent(searchTarget),
    timeout: 60000
  });
  const sr = searchResp.esearchresult || {};
  const totalCount = Math.min(parseInt(sr.count || '0'), MAX_RESULTS);
  const webEnv = sr.webenv || '';
  const queryKey = sr.querykey || '';
  console.log(`PubMed fetch: ${sr.count} found, fetching up to ${totalCount}`);
  if (totalCount === 0 || !webEnv) {
    return [{ json: { _source: 'pubmed', _empty: true } }];
  }

  for (let retStart = 0; retStart < totalCount; retStart += BATCH) {
    const fetchTarget = `https://eutils.ncbi.nlm.nih.gov/entrez/eutils/efetch.fcgi?db=pubmed&WebEnv=${encodeURIComponent(webEnv)}&query_key=${queryKey}&retstart=${retStart}&retmax=${BATCH}&rettype=xml&retmode=xml`;
    let xmlText;
    try {
      const xmlResp = await this.helpers.httpRequest({
        method: 'GET',
        url: PROXY + '?url=' + encodeURIComponent(fetchTarget),
        timeout: 120000
      });
      xmlText = typeof xmlResp === 'string' ? xmlResp : JSON.stringify(xmlResp);
    } catch(e) {
      console.log('PubMed batch error at ' + retStart + ': ' + e.message);
      continue;
    }
    const blocks = xmlText.split('<PubmedArticle>');
    for (let i = 1; i < blocks.length; i++) {
      const b = blocks[i];
      const title = ((b.match(/<ArticleTitle>([\s\S]*?)<\/ArticleTitle>/) || [])[1] || '').replace(/<[^>]+>/g, '').trim();
      let abstract = '';
      const absMatch = b.match(/<Abstract>([\s\S]*?)<\/Abstract>/);
      if (absMatch) {
        const parts = absMatch[1].match(/<AbstractText[^>]*>([\s\S]*?)<\/AbstractText>/g);
        if (parts) abstract = parts.map(t => t.replace(/<[^>]*>/g, '').trim()).join(' ');
      }
      const authors = [];
      const authMatches = b.match(/<Author[^>]*>[\s\S]*?<\/Author>/g);
      if (authMatches) {
        for (const a of authMatches) {
          const last = ((a.match(/<LastName>([^<]+)<\/LastName>/) || [])[1] || '');
          const fore = ((a.match(/<ForeName>([^<]+)<\/ForeName>/) || [])[1] || '');
          if (last) authors.push((fore + ' ' + last).trim());
        }
      }
      const year = ((b.match(/<PubDate>[\s\S]*?<Year>(\d{4})<\/Year>/) || [])[1] || '');
      const journal = ((b.match(/<Title>([^<]+)<\/Title>/) || [])[1] || '').trim();
      const doi = ((b.match(/<ArticleId IdType="doi">([^<]+)<\/ArticleId>/) || [])[1] || '').trim();
      const pmid = ((b.match(/<PMID[^>]*>(\d+)<\/PMID>/) || [])[1] || '');
      const volume = ((b.match(/<Volume>([^<]+)<\/Volume>/) || [])[1] || '').trim();
      const issue = ((b.match(/<Issue>([^<]+)<\/Issue>/) || [])[1] || '').trim();
      const pages = ((b.match(/<MedlinePgn>([^<]+)<\/MedlinePgn>/) || [])[1] || '').trim();
      if (title) {
        allArticles.push({
          _source: 'pubmed', pmid, doi, title, abstract, authors, year, journal, volume, issue, pages
        });
      }
    }
    console.log(`PubMed batch ${retStart}: total=${allArticles.length}`);
    await new Promise(r => setTimeout(r, 400));
  }
} catch(e) {
  console.log('PubMed fatal: ' + e.message);
}

console.log('PubMed DONE: ' + allArticles.length);
if (allArticles.length === 0) return [{ json: { _source: 'pubmed', _empty: true } }];
return allArticles.map(a => ({ json: a }));

// OPENALEX FETCH avec cap par source
const input = $('Extract Params').first().json;
const query = encodeURIComponent(input.openalex_query || '');
const PROXY = 'http://host.docker.internal:3456';
const PER_PAGE = 200;
const cap = parseInt(input.cap_openalex) || 0;
const unlimited = input.unlimited === true;
const MAX_RESULTS = unlimited ? Number.MAX_SAFE_INTEGER : (cap > 0 ? cap : 1000);

let cursor = '*';
let allResults = [];
let pageNum = 0;

if (!query) return [{ json: { _source: 'openalex', _empty: true } }];

try {
  while (cursor && allResults.length < MAX_RESULTS) {
    pageNum++;
    const targetUrl = `https://api.openalex.org/works?search=${query}&per-page=${PER_PAGE}&cursor=${encodeURIComponent(cursor)}&select=id,doi,title,display_name,abstract_inverted_index,authorships,publication_year,primary_location,biblio&mailto=ultralab@review.org`;
    let resp;
    try {
      resp = await this.helpers.httpRequest({ method: 'GET', url: PROXY + '?url=' + encodeURIComponent(targetUrl), timeout: 120000 });
    } catch(e) {
      console.log('OpenAlex HTTP error page ' + pageNum + ': ' + e.message);
      break;
    }
    const works = resp.results || [];
    if (works.length === 0) break;
    for (const w of works) {
      const journal = (w.primary_location && w.primary_location.source) ? (w.primary_location.source.display_name || '') : '';
      let abstract = '';
      if (w.abstract_inverted_index) {
        const pairs = [];
        for (const [word, positions] of Object.entries(w.abstract_inverted_index)) {
          for (const pos of positions) pairs.push([pos, word]);
        }
        pairs.sort((a, b) => a[0] - b[0]);
        abstract = pairs.map(p => p[1]).join(' ');
      }
      const authors = (w.authorships || []).map(a => a.author ? a.author.display_name : '').filter(Boolean);
      const biblio = w.biblio || {};
      allResults.push({
        _source: 'openalex',
        openalex_id: (w.id || '').replace('https://openalex.org/', ''),
        doi: (w.doi || '').replace('https://doi.org/', ''),
        title: w.display_name || w.title || '',
        abstract, authors,
        year: w.publication_year || '',
        journal,
        volume: biblio.volume || '',
        issue: biblio.issue || '',
        pages: (biblio.first_page && biblio.last_page) ? (biblio.first_page + '-' + biblio.last_page) : (biblio.first_page || '')
      });
    }
    cursor = (resp.meta && resp.meta.next_cursor) ? resp.meta.next_cursor : null;
    console.log(`OpenAlex page ${pageNum}: total=${allResults.length}`);
    await new Promise(r => setTimeout(r, 150));
  }
} catch(e) {
  console.log('OpenAlex fatal: ' + e.message);
}

console.log('OpenAlex DONE: ' + allResults.length);
if (allResults.length === 0) return [{ json: { _source: 'openalex', _empty: true } }];
return allResults.slice(0, MAX_RESULTS).map(r => ({ json: r }));

// CROSSREF FETCH avec cap par source
const input = $('Extract Params').first().json;
const query = encodeURIComponent(input.crossref_query || '');
const PROXY = 'http://host.docker.internal:3456';
const ROWS = 200;
const cap = parseInt(input.cap_crossref) || 0;
const unlimited = input.unlimited === true;
const MAX_RESULTS = unlimited ? Number.MAX_SAFE_INTEGER : (cap > 0 ? cap : 1000);

let cursor = '*';
let allResults = [];
let pageNum = 0;

if (!query) return [{ json: { _source: 'crossref', _empty: true } }];

try {
  while (cursor && allResults.length < MAX_RESULTS) {
    pageNum++;
    const targetUrl = `https://api.crossref.org/works?query=${query}&rows=${ROWS}&cursor=${encodeURIComponent(cursor)}&select=DOI,title,abstract,author,published,container-title,volume,issue,page,type&mailto=ultralab@review.org`;
    let resp;
    try {
      resp = await this.helpers.httpRequest({ method: 'GET', url: PROXY + '?url=' + encodeURIComponent(targetUrl), timeout: 120000 });
    } catch(e) {
      console.log('Crossref HTTP error page ' + pageNum + ': ' + e.message);
      break;
    }
    const items = (resp.message && resp.message.items) ? resp.message.items : [];
    if (items.length === 0) break;
    for (const w of items) {
      const authors = (w.author || []).map(a => [a.given, a.family].filter(Boolean).join(' ')).filter(Boolean);
      const title = Array.isArray(w.title) ? w.title[0] || '' : (w.title || '');
      const journal = Array.isArray(w['container-title']) ? w['container-title'][0] || '' : (w['container-title'] || '');
      let year = '';
      if (w.published && w.published['date-parts'] && w.published['date-parts'][0]) year = w.published['date-parts'][0][0] || '';
      allResults.push({
        _source: 'crossref',
        doi: w.DOI || '',
        title,
        abstract: (w.abstract || '').replace(/<[^>]+>/g, ''),
        authors,
        year: String(year),
        journal,
        volume: w.volume || '',
        issue: w.issue || '',
        pages: w.page || '',
        type: w.type || ''
      });
    }
    cursor = (resp.message && resp.message['next-cursor']) ? resp.message['next-cursor'] : null;
    console.log(`Crossref page ${pageNum}: total=${allResults.length}`);
    await new Promise(r => setTimeout(r, 150));
  }
} catch(e) {
  console.log('Crossref fatal: ' + e.message);
}

console.log('Crossref DONE: ' + allResults.length);
if (allResults.length === 0) return [{ json: { _source: 'crossref', _empty: true } }];
return allResults.slice(0, MAX_RESULTS).map(r => ({ json: r }));

// GENERATE NBIB + SAVE FILE
// Format MEDLINE/nbib :
//   TAG - VALUE
//   Article separator : ligne vide
//
// Tags utilises :
//   PMID, PT (publication type), TI, AU, FAU, DP (date), TA (journal abbrev),
//   JT (journal full), AB (abstract), AID (article ID = doi), VI (volume),
//   IP (issue), PG (pages), LID (location ID), OWN (owner), STAT
const fs = require('fs');
const path = require('path');

const allItems = $input.all().map(i => i.json).filter(a => !a._empty);
const inputParams = $('Extract Params').first().json;
const capGlobal = parseInt(inputParams.cap_global) || 0;
const unlimited = inputParams.unlimited === true;

// Apply global cap (apres merge de toutes les sources)
let articles = allItems;
if (!unlimited && capGlobal > 0 && articles.length > capGlobal) {
  console.log(`Apply cap_global ${capGlobal} on ${articles.length} -> ${capGlobal}`);
  articles = articles.slice(0, capGlobal);
}

const counts = { pubmed: 0, openalex: 0, crossref: 0 };
for (const a of articles) {
  if (counts[a._source] !== undefined) counts[a._source]++;
}

// Format MEDLINE one entry
function fmt(tag, value) {
  if (!value && value !== 0) return '';
  const v = String(value).replace(/\r/g, '').replace(/\n/g, ' ').trim();
  if (!v) return '';
  // MEDLINE format : 4 chars tag, " - ", value, continuation lines indented 6 spaces
  // For simplicity we don't wrap long lines (nbib parsers handle long lines).
  return tag.padEnd(4) + '- ' + v + '\n';
}

function toNbib(a) {
  let out = '';
  // PMID first if available
  if (a.pmid) out += fmt('PMID', a.pmid);
  out += fmt('OWN', 'NLM');
  out += fmt('STAT', 'MEDLINE');
  out += fmt('PT', 'Journal Article');
  // Title
  out += fmt('TI', a.title);
  // Authors
  if (Array.isArray(a.authors)) {
    for (const au of a.authors) {
      if (au) {
        out += fmt('FAU', au);
        // Build AU as "Surname FI" if possible (assume "First Last")
        const parts = au.trim().split(/\s+/);
        if (parts.length >= 2) {
          const last = parts[parts.length - 1];
          const initials = parts.slice(0, -1).map(p => p.charAt(0).toUpperCase()).join('');
          out += fmt('AU', last + ' ' + initials);
        } else {
          out += fmt('AU', au);
        }
      }
    }
  }
  // Journal info
  if (a.journal) {
    out += fmt('JT', a.journal);
    out += fmt('TA', a.journal);
  }
  if (a.volume) out += fmt('VI', a.volume);
  if (a.issue) out += fmt('IP', a.issue);
  if (a.pages) out += fmt('PG', a.pages);
  // Date
  if (a.year) out += fmt('DP', a.year);
  // Abstract
  if (a.abstract) out += fmt('AB', a.abstract);
  // IDs
  if (a.doi) {
    out += fmt('AID', a.doi + ' [doi]');
    out += fmt('LID', a.doi + ' [doi]');
  }
  if (a.openalex_id) out += fmt('LID', a.openalex_id + ' [openalex]');
  // Source tag (custom, mais utile pour traçabilite)
  out += fmt('SO', '[source:' + a._source + ']');
  return out + '\n';
}

const nbibContent = articles.map(toNbib).join('');

// Sauvegarde fichier
// output_folder vient du parametre user (ex: /desktop/MaRecherche)
// le volume docker mappe /desktop -> Desktop user
let outputFolder = (inputParams.output_folder || '/desktop').trim();
if (!outputFolder.startsWith('/desktop')) {
  // Securite : forcer dans /desktop pour eviter ecriture hors zone
  outputFolder = '/desktop';
}
try {
  if (!fs.existsSync(outputFolder)) fs.mkdirSync(outputFolder, { recursive: true });
} catch(e) {
  console.log('mkdir error: ' + e.message);
}

const timestamp = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
const filename = 'ultralab-search-' + timestamp + '.nbib';
const fullPath = path.join(outputFolder, filename);

let saveSuccess = false;
let saveError = null;
try {
  fs.writeFileSync(fullPath, nbibContent, 'utf-8');
  saveSuccess = true;
  console.log('NBIB saved: ' + fullPath + ' (' + articles.length + ' articles, ' + nbibContent.length + ' bytes)');
} catch(e) {
  saveError = e.message;
  console.log('NBIB save error: ' + e.message);
}

return [{ json: {
  action: 'search',
  success: saveSuccess,
  file_path: fullPath,
  file_name: filename,
  output_folder: outputFolder,
  bytes: nbibContent.length,
  total_articles: articles.length,
  count_by_source: counts,
  capped: !unlimited && capGlobal > 0 && allItems.length > capGlobal,
  original_total: allItems.length,
  error: saveError
}}];
